// FB Lead Ads gửi nested format
const entry = $input.first().json.body.entry?.[0];
const change = entry?.changes?.[0];
const lead = change?.value;
if (!lead) return [{ json: { error: 'invalid_payload' } }];
const fields = {};
(lead.field_data || []).forEach(f => { fields[f.name] = f.values?.[0]; });
return [{ json: {
  fb_lead_id: lead.leadgen_id,
  form_id: lead.form_id,
  full_name: fields.full_name || fields.name,
  phone: fields.phone_number || fields.phone,
  email: fields.email,
  budget: fields.budget,
  raw: fields
} }];
